// Build HTML notification for order submission results
const input = $input.first().json;
const lines = input.validatedLines || [];
const invalidLines = input.invalidLines || [];
const summary = input.summary || { valid: 0, invalid: 0, warnings: 0 };
const senderEmail = input.senderEmail || 'unknown';
const emailSubject = input.emailSubject || 'N/A';
const submissionResult = input.submissionResult || {};

// Submission results banner
const success = submissionResult.submitted || false;
const bannerColor = success ? '#d4edda' : '#f8d7da';
const bannerTextColor = success ? '#155724' : '#721c24';
const statusText = success ? 'ORDER SUBMITTED SUCCESSFULLY' : 'ORDER SUBMISSION FAILED';

let html = `<div style="padding:12px 16px;background:${bannerColor};color:${bannerTextColor};border-radius:6px;margin-bottom:16px;font-weight:bold;">`;
html += statusText;
if (submissionResult.orders && submissionResult.orders.length > 0) {
  html += `<br>Order IDs: ${submissionResult.orders.map(o => o.orderId).join(', ')}`;
}
if (submissionResult.errors && submissionResult.errors.length > 0) {
  html += `<br>Errors: ${submissionResult.errors.map(e => e.error).join('; ')}`;
}
html += `</div>`;

html += `<h2>Pre-Order Notification</h2>`;
html += `<p><strong>From:</strong> ${senderEmail}<br>`;
html += `<strong>Subject:</strong> ${emailSubject}<br>`;
html += `<strong>Lines:</strong> ${lines.length} | `;
html += `<strong>Valid:</strong> ${summary.valid} | `;
html += `<strong>Invalid:</strong> ${summary.invalid} | `;
html += `<strong>With Warnings:</strong> ${summary.warnings}</p>`;

html += `<table border="1" cellpadding="5" cellspacing="0" style="border-collapse:collapse;font-size:13px;">`;
html += `<tr style="background:#f0f0f0;"><th>#</th><th>Pharmacy ID</th><th>Pharmacy</th><th>Customer ID</th><th>Article ID</th><th>Article Name</th><th>Qty</th><th>Unit</th></tr>`;

const allLines = [...lines, ...invalidLines];
for (let i = 0; i < allLines.length; i++) {
  const line = allLines[i];
  const bgColor = !line.valid ? '#ffe0e0' :
                  line.warnings && line.warnings.length > 0 ? '#fff3cd' :
                  line.parseMethod === 'AI_EXTRACTED' ? '#e0e7ff' : '#e0ffe0';

  html += `<tr style="background:${bgColor};">`;
  html += `<td>${i + 1}</td>`;
  html += `<td>${line.pharmacyId || line.deliveryPlace || '-'}</td>`;
  html += `<td>${line.pharmacyName || line.deliveryPlaceName || '-'}</td>`;
  html += `<td>${line.customer || '-'}</td>`;
  html += `<td>${line.articleId || line.drugCode || '-'}</td>`;
  html += `<td>${line.articleName || '-'}</td>`;
  html += `<td>${line.quantity}</td>`;
  html += `<td>${line.unit || 'kom'}</td>`;
  html += `</tr>`;
}
html += `</table>`;

if (summary.invalid > 0) {
  html += `<p style="color:red;"><strong>Warning:</strong> ${summary.invalid} line(s) have validation errors and were skipped.</p>`;
}

const aiLines = allLines.filter(l => l.parseMethod === 'AI_EXTRACTED');
if (aiLines.length > 0) {
  html += `<p style="color:#3b5998;"><strong>Note:</strong> ${aiLines.length} line(s) were extracted by AI (highlighted in blue).</p>`;
}

// Original email body
const emailBodyHtml = input.emailBodyHtml || '';
if (emailBodyHtml) {
  html += `<hr style="margin:20px 0;">`;
  html += `<h3>Original Email</h3>`;
  html += `<blockquote style="border-left:3px solid #ccc;padding:8px 16px;margin:8px 0;color:#555;">${emailBodyHtml}</blockquote>`;
}

const binary = $input.first().binary || {};
const hasAttachment = !!(binary.data);

return [{
  json: {
    ...input,
    notificationHtml: html,
    _hasAttachment: hasAttachment
  },
  binary: binary
}];
